     5→/// Service for handling authentication operations with AWS Cognito
     6→class AuthService {
     7→  final CognitoUserPool _userPool;
     8→  CognitoUser? _cognitoUser;
     9→  CognitoUserSession? _session;
    10→
    11→  /// Creates a new [AuthService] with the given user pool
    12→  AuthService({
    13→    required CognitoUserPool userPool,
    14→  }) : _userPool = userPool;
    15→
    16→  /// Get the current authentication token
    17→  String? get token => _session?.getAccessToken().getJwtToken();
    18→
    19→  /// Get the current username
    20→  String? get username => _cognitoUser?.username;
    21→
    22→  /// Check if a user is authenticated
    23→  bool get isAuthenticated => _session?.isValid() ?? false;
    24→
    25→  /// Initialize the auth service
    26→  Future<void> initialize() async {
    27→    // Check for existing session
    28→    if (_cognitoUser != null) {
    29→      try {
    30→        _session = await _cognitoUser!.getSession();
    31→      } catch (e) {
    32→        debugPrint('Failed to restore session: $e');
    33→      }
    34→    }
    35→  }
    36→
    37→  /// Sign in with username and password
    38→  Future<bool> signIn({
    39→    required String username,
    40→    required String password,
    41→  }) async {
    42→    try {
    43→      debugPrint('Attempting to sign in user: $username');
    44→      _cognitoUser = CognitoUser(username, _userPool);
    45→
    46→      final authDetails = AuthenticationDetails(
    47→        username: username,
    48→        password: password,
    49→      );
    50→
    51→      _session = await _cognitoUser!.authenticateUser(authDetails);
    52→
    53→      if (_session == null) {
    54→        throw const AuthException(
    55→          'Unable to sign in. Please try again.',
    56→          code: 'AUTHENTICATION_FAILED',
    57→        );
    58→      }
    59→
    60→      debugPrint('Sign in successful');
    61→      return true;
    62→    } catch (e) {
    63→      debugPrint('Sign in failed: $e');
    64→      _session = null;
    65→      _cognitoUser = null;
    66→      return false;
    67→    }
    68→  }
    69→
    70→  /// Refresh the current session
    71→  Future<bool> refreshSession() async {
    72→    if (_cognitoUser == null || _session == null) {
    73→      return false;
    74→    }
    75→
    76→    try {
    77→      _session =
    78→          await _cognitoUser!.refreshSession(_session!.getRefreshToken()!);
    79→      return _session?.isValid() ?? false;
    80→    } catch (e) {
    81→      debugPrint('Failed to refresh session: $e');
    82→      return false;
    83→    }
    84→  }
    85→
    86→  /// Sign out the current user
    87→  Future<void> signOut() async {
    88→    try {
    89→      await _cognitoUser?.signOut();
    90→    } finally {
    91→      _session = null;
    92→      _cognitoUser = null;
    93→    }
    94→  }
    95→}
