   240→        _emitDisconnectedStatus();
   241→      },
   242→    );
   243→  }
   244→
   245→  /// Stop monitoring connectivity changes
   246→  void _stopMonitoring() {
   247→    debugPrint('🌐 Stopping connectivity monitoring...');
   248→
   249→    _debounceTimer?.cancel();
   250→    _debounceTimer = null;
   251→
   252→    _connectivitySubscription?.cancel();
   253→    _connectivitySubscription = null;
   254→  }
   255→
   256→  /// Handle connectivity change with debouncing
   257→  void _handleConnectivityChange(List<ConnectivityResult> results) {
   258→    // Cancel any pending debounce timer
   259→    _debounceTimer?.cancel();
   260→
   261→    final newStatus = ConnectivityStatus.fromConnectivityResult(results);
   262→
   263→    // If status hasn't changed, skip emitting
