   131→/// Service to monitor network connectivity changes
   132→///
   133→/// This service provides a stream-based API for monitoring network connectivity
   134→/// changes. It handles debouncing to prevent rapid status changes and provides
   135→/// initial connectivity check on startup.
   136→///
   137→/// Example usage:
   138→/// ```dart
   139→/// final connectivityService = ConnectivityService();
   140→///
   141→/// // Listen to connectivity changes
   142→/// connectivityService.connectivityStream.listen((status) {
   143→///   print('Connected: ${status.isConnected}');
   144→///   print('Type: ${status.connectionType}');
   145→/// });
   146→///
   147→/// // Check current connectivity
   148→/// final currentStatus = await connectivityService.checkConnectivity();
   149→/// ```
   150→class ConnectivityService {
   151→  /// Connectivity plugin instance
   152→  final Connectivity _connectivity;
   153→
   154→  /// Stream controller for connectivity status updates
   155→  StreamController<ConnectivityStatus>? _streamController;
   156→
   157→  /// Subscription to connectivity plugin's onConnectivityChanged stream
   158→  StreamSubscription<List<ConnectivityResult>>? _connectivitySubscription;
   159→
   160→  /// Timer for debouncing connectivity changes
   161→  Timer? _debounceTimer;
   162→
   163→  /// Debounce delay to prevent rapid status changes (milliseconds)
   164→  final int debounceMs;
   165→
   166→  /// Last emitted connectivity status
   167→  ConnectivityStatus? _lastStatus;
   168→
   169→  /// Creates a new [ConnectivityService] instance
   170→  ///
   171→  /// [connectivity] - Connectivity plugin instance (defaults to Connectivity())
   172→  /// [debounceMs] - Debounce delay in milliseconds (default: 300ms)
   173→  ConnectivityService({
   174→    Connectivity? connectivity,
   175→    this.debounceMs = 300,
   176→  }) : _connectivity = connectivity ?? Connectivity();
   177→
   178→  /// Stream of connectivity status updates
   179→  ///
   180→  /// This stream emits a new [ConnectivityStatus] whenever the network
   181→  /// connectivity changes. The stream is debounced to prevent rapid
   182→  /// successive updates.
   183→  Stream<ConnectivityStatus> get connectivityStream {
   184→    _streamController ??= StreamController<ConnectivityStatus>.broadcast(
   185→      onListen: _startMonitoring,
   186→      onCancel: _stopMonitoring,
   187→    );
   188→
   189→    return _streamController!.stream;
   190→  }
   191→
   192→  /// Check current connectivity status
   193→  ///
   194→  /// Returns the current connectivity status without starting the monitoring
   195→  /// stream. This is useful for one-time checks.
   196→  Future<ConnectivityStatus> checkConnectivity() async {
   197→    try {
   198→      final results = await _connectivity.checkConnectivity();
   199→      final status = ConnectivityStatus.fromConnectivityResult(results);
   200→
   201→      _lastStatus = status;
   202→
   203→      debugPrint('🌐 Connectivity check: ${status.connectionType} '
   204→          '(connected: ${status.isConnected})');
   205→
   206→      return status;
   207→    } catch (e) {
   208→      debugPrint('❌ Error checking connectivity: $e');
   209→
   210→      // Return disconnected status on error
   211→      final status = ConnectivityStatus.disconnected();
   212→      _lastStatus = status;
   213→      return status;
   214→    }
   215→  }
   216→
   217→  /// Start monitoring connectivity changes
   218→  void _startMonitoring() {
   219→    if (_connectivitySubscription != null) {
   220→      // Already monitoring
   221→      return;
   222→    }
   223→
   224→    debugPrint('🌐 Starting connectivity monitoring...');
   225→
   226→    // Perform initial check
   227→    checkConnectivity().then((status) {
   228→      if (_streamController != null && !_streamController!.isClosed) {
   229→        _streamController!.add(status);
   230→      }
   231→    });
   232→
   233→    // Listen to connectivity changes
   234→    _connectivitySubscription = _connectivity.onConnectivityChanged.listen(
   235→      (results) {
   236→        _handleConnectivityChange(results);
